final class Accumulator {
  var values: [Int] = []
}

func start(_ accumulator: Accumulator) {
  Task.detached {
    accumulator.values.append(1)
  }
}

actor Accumulator {
  private var values: [Int] = []

  func append(_ value: Int) {
    values.append(value)
  }
}

func start(_ accumulator: Accumulator) {
  Task {
    await accumulator.append(1)
  }
}
